document.addEventListener("DOMContentLoaded", function () {
  var btn = document.getElementById("catalogMegaBtn") || document.getElementById("ozonCatalogToggle");
  if (!btn) return;

  var menu = document.getElementById("catalogMega") || document.getElementById("ozonMegaMenu");
  if (!menu) return;

  var wrap = document.getElementById("catalogMegaWrap") || btn.closest(".ozon-header") || btn.parentElement;
  var sidebar = document.getElementById("catalogMegaSidebar") || document.getElementById("ozonMegaSidebar");
  var content = document.getElementById("catalogMegaContent") || (sidebar ? sidebar.nextElementSibling : null);
  var panels = content ? content.querySelectorAll(".ozon-mega-content-panel") : document.querySelectorAll(".ozon-mega-content-panel");
  var items = sidebar ? sidebar.querySelectorAll(".ozon-mega-item") : [];

  function activate(item) {
    var id = item.getAttribute("data-category-id");
    items.forEach(function (el) { el.classList.remove("active"); });
    item.classList.add("active");
    panels.forEach(function (p) {
      p.style.display = p.getAttribute("data-category-id") === id ? "block" : "none";
    });
  }

  function closeMenu() {
    if (menu.classList.contains("open")) {
      menu.classList.remove("open");
      menu.classList.add("closing");
      btn.classList.remove("active");
      setTimeout(function () {
        menu.style.display = "none";
        menu.classList.remove("closing");
      }, 200);
    } else {
      menu.style.display = "none";
      btn.classList.remove("active");
    }
  }

  btn.addEventListener("click", function (ev) {
    ev.stopPropagation();
    if (menu.style.display !== "none" && menu.classList.contains("open")) {
      closeMenu();
    } else {
      menu.style.display = "block";
      menu.classList.remove("closing");
      menu.offsetHeight;
      menu.classList.add("open");
      btn.classList.add("active");
    }
  });

  document.addEventListener("click", function (ev) {
    if (!wrap.contains(ev.target)) closeMenu();
  });

  var isTouch = function () {
    return window.matchMedia("(hover: none)").matches || window.innerWidth <= 1024;
  };

  items.forEach(function (item) {
    item.addEventListener("mouseenter", function () {
      if (!isTouch()) activate(item);
    });
    item.addEventListener("click", function (ev) {
      if (isTouch()) {
        ev.preventDefault();
        var id = item.getAttribute("data-category-id");
        var panel = content ? content.querySelector('.ozon-mega-content-panel[data-category-id="' + id + '"]') : null;
        if (panel) {
          panel.style.display = panel.style.display === "block" ? "none" : "block";
        }
        activate(item);
      }
    });
  });
});
